/*Table structure for table `tbl_rebooking` */

DROP TABLE IF EXISTS `tbl_rebooking`;

CREATE TABLE `tbl_rebooking` (
  `r_id` int(11) NOT NULL AUTO_INCREMENT,
  `r_fID` int(11) DEFAULT NULL,
  `r_flightno` varchar(100) DEFAULT NULL,
  `r_reference` varchar(100) DEFAULT NULL,
  `r_flight_num` varchar(50) DEFAULT NULL,
  `r_airline` varchar(50) DEFAULT NULL,
  `r_original_route` varchar(50) DEFAULT NULL,
  `r_origin` varchar(50) DEFAULT NULL,
  `r_destination` varchar(50) DEFAULT NULL,
  `r_date` date DEFAULT NULL,
  `r_time` time DEFAULT NULL,
  `r_reason` longtext,
  `r_initiatedby` varchar(50) DEFAULT NULL,
  `r_estimated_price` double(50,10) DEFAULT NULL,
  `r_service_fee` double(50,10) DEFAULT NULL,
  `r_actual_price` double(50,10) DEFAULT NULL,
  `r_reviwed_by` varchar(50) DEFAULT NULL,
  `r_reviwed_date` date DEFAULT NULL,
  `r_approved_by` varchar(50) DEFAULT NULL,
  `r_approved_sign` longtext,
  `r_approved_date` date DEFAULT NULL,
  `r_status` varchar(20) DEFAULT NULL,
  `r_cancel_reason` varchar(300) DEFAULT NULL,
  `r_rebookby` varchar(50) DEFAULT NULL,
  `r_rebook_date` date DEFAULT NULL,
  `r_attachment` longtext,
  `r_timestamp` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`r_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=latin1;

/*Data for the table `tbl_rebooking` */

